namespace parser::event {
        bool RecursionGuard::inline_table_open(::source::Span span, auto& error) {
            const auto allowed = ::parser::event::rusty_ext::inline_table_open(this->receiver, std::move(span), error);
            [&]() { static_cast<void>(this->depth += 1); return std::make_tuple(); }();
            const auto within_depth = this->within_depth();
            if (allowed && !within_depth) {
                ::error::rusty_ext::report_error(error, ParseError::new_("cannot recurse further; max recursion depth met").with_unexpected(std::move(span)));
            }
            return allowed && within_depth;
        }
}

namespace parser::event {
        void RecursionGuard::inline_table_close(::source::Span span, auto& error) {
            [&]() { static_cast<void>(this->depth -= 1); return std::make_tuple(); }();
            ::parser::event::rusty_ext::inline_table_close(this->receiver, std::move(span), error);
        }
}

