            rusty::Result<rusty::String&, ser::error::Error> serialize_i8(int8_t v);
            rusty::Result<rusty::String&, ser::error::Error> serialize_i16(int16_t v);
            rusty::Result<rusty::String&, ser::error::Error> serialize_i32(int32_t v);
            rusty::Result<rusty::String&, ser::error::Error> serialize_i64(int64_t v);
            rusty::Result<rusty::String&, ser::error::Error> serialize_i128(__int128 v);
