template<typename T>
rusty::Result<T, de::Error> value_from_str(std::string_view s) {
    return T::deserialize(RUSTY_TRY_INTO(toml::de::ValueDeserializer<auto>::parse(s), rusty::Result<T, de::Error>));
}

template<typename T>
rusty::Result<rusty::String, ser::Error> to_string_value(const T& value) {
    auto output = std::conditional_t<true, rusty::String, T>::new_();
    const auto serializer = std::conditional_t<true, ser::ValueSerializer, T>::new_(output);
    RUSTY_TRY_INTO(([&](auto&& __self, auto&& __serializer) -> decltype(auto) { if constexpr (requires { std::forward<decltype(__self)>(__self).serialize(std::forward<decltype(__serializer)>(__serializer)); }) { return std::forward<decltype(__self)>(__self).serialize(std::forward<decltype(__serializer)>(__serializer)); } else { return ::ser::impls::rusty_ext::serialize(std::forward<decltype(__self)>(__self), std::forward<decltype(__serializer)>(__serializer)); } })(value, std::move(serializer)), rusty::Result<rusty::String, ser::Error>);
    return rusty::Result<rusty::String, ser::Error>::Ok(std::move(output));
}

